class Tonemap(BaseNode):
    """
    Map one set of colors to another in order to approximate the appearance of high dynamic range

    Parameters
    ----------
    image : InputColor
        Image
    type : InputMenu | Literal['R/D Photoreceptor', 'Rh Simple']
        Type
    key : InputFloat
        Key
    balance : InputFloat
        Balance
    gamma : InputFloat
        Gamma
    intensity : InputFloat
        Intensity
    contrast : InputFloat
        Contrast
    light_adaptation : InputFloat
        Light Adaptation
    chromatic_adaptation : InputFloat
        Chromatic Adaptation

    Inputs
    ------
    i.image : ColorSocket
        Image
    i.type : MenuSocket
        Type
    i.key : FloatSocket
        Key
    i.balance : FloatSocket
        Balance
    i.gamma : FloatSocket
        Gamma
    i.intensity : FloatSocket
        Intensity
    i.contrast : FloatSocket
        Contrast
    i.light_adaptation : FloatSocket
        Light Adaptation
    i.chromatic_adaptation : FloatSocket
        Chromatic Adaptation

    Outputs
    -------
    o.image : ColorSocket
        Image
    """

    _bl_idname = "CompositorNodeTonemap"
    node: bpy.types.CompositorNodeTonemap

    class _Inputs(SocketAccessor):
        image: ColorSocket
        """Image"""
        type: MenuSocket
        """Type"""
        key: FloatSocket
        """Key"""
        balance: FloatSocket
        """Balance"""
        gamma: FloatSocket
        """Gamma"""
        intensity: FloatSocket
        """Intensity"""
        contrast: FloatSocket
        """Contrast"""
        light_adaptation: FloatSocket
        """Light Adaptation"""
        chromatic_adaptation: FloatSocket
        """Chromatic Adaptation"""

    class _Outputs(SocketAccessor):
        image: ColorSocket
        """Image"""

    if TYPE_CHECKING:

        @property
        def i(self) -> _Inputs: ...
        @property
        def o(self) -> _Outputs: ...

    def __init__(
        self,
        image: InputColor = None,
        type: InputMenu
        | Literal["R/D Photoreceptor", "Rh Simple"] = "R/D Photoreceptor",
        key: InputFloat = 0.18,
        balance: InputFloat = 1.0,
        gamma: InputFloat = 1.0,
        intensity: InputFloat = 0.0,
        contrast: InputFloat = 0.0,
        light_adaptation: InputFloat = 0.0,
        chromatic_adaptation: InputFloat = 0.0,
    ):
        super().__init__()
        key_args = {
            "Image": image,
            "Type": type,
            "Key": key,
            "Balance": balance,
            "Gamma": gamma,
            "Intensity": intensity,
            "Contrast": contrast,
            "Light Adaptation": light_adaptation,
            "Chromatic Adaptation": chromatic_adaptation,
        }

        self._establish_links(**key_args)

    @classmethod
    def r_d_photoreceptor(
        cls,
        image: InputColor = None,
        intensity: InputFloat = 0.0,
        contrast: InputFloat = 0.0,
        light_adaptation: InputFloat = 0.0,
        chromatic_adaptation: InputFloat = 0.0,
    ) -> "Tonemap":
        """Create Tonemap node with type 'R/D Photoreceptor'."""
        return cls(
            image=image,
            intensity=intensity,
            contrast=contrast,
            light_adaptation=light_adaptation,
            chromatic_adaptation=chromatic_adaptation,
            type="R/D Photoreceptor",
        )

    @classmethod
    def rh_simple(
        cls,
        image: InputColor = None,
        key: InputFloat = 0.18,
        balance: InputFloat = 1.0,
        gamma: InputFloat = 1.0,
    ) -> "Tonemap":
        """Create Tonemap node with type 'Rh Simple'."""
        return cls(image=image, key=key, balance=balance, gamma=gamma, type="Rh Simple")
